var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BUTLER_PRIDE_NULL_NULL","text":{"KOREA":"고생하셨습니다, 그레이스 님. 이번 무구의 선별은 평소보다 순조로우셨나 보군요.","JPN":"お疲れ様でした、グレース様。今回の武具の選別はいつもより順調だったようですね。","ENG":"Welcome back, Dame Grace. It seems the selection of your Armament went more smoothly than usual this time.","TWN":"辛苦了，葛瑞絲小姐。這次武器的挑選似乎比平時順利呢。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 물병자리의 가호를 받은 대로 물처럼 맑은 여식이었습니다.","JPN":"ええ。水瓶座の加護を受けるにふさわしい、水のように澄んだ娘でした。","ENG":"Indeed. As if blessed by Aquarius, the young lady I met was as clear and calm as water.","TWN":"是的。她是受到水瓶座守護的，如水般清澈的女孩。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예정보다 이른 시간에 복귀한 탓에, 루지에가 불만이 많아보였지만요.","JPN":"予定より早く復帰したので、ルージは不満そうでしたが。","ENG":"I returned earlier than planned, so Rougié looked quite displeased.","TWN":"由於比預定時間提前返回，路吉爾似乎有很多不滿。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BUTLER_PRIDE_NULL_NULL","text":{"KOREA":"이번에도 단원들에게 당부 없이 돌아오신 겁니까?","JPN":"また団員たちに事前告知もなくお戻りになったのですか？","ENG":"You left without saying a word to your knights again, didn't you?","TWN":"這次也是沒有通知團員就回來了吧？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"깜짝 놀라게 할 생각이었는지라.","JPN":"びっくりさせたいと思いましたので。","ENG":"Well, I did want to surprise them.","TWN":"本來就是想嚇你一跳的。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BUTLER_PRIDE_NULL_NULL","text":{"KOREA":"……확실히 놀랐겠군요, 그건.","JPN":"……それは確かにびっくりしますね。","ENG":"...Yes, I'm sure they were very surprised.","TWN":"……確實讓人吃驚。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BUTLER_PRIDE_NULL_NULL","text":{"KOREA":"받으시죠. 노인의 얕은 식견으로 우려낸 차입니다.","JPN":"どうぞ。年寄りの浅知恵で淹れたお茶です。","ENG":"Here. A simple brew from an old man's shallow wisdom.","TWN":"請享用。這是我剛才泡好的茶。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아… 감사합니다.","JPN":"あ……ありがとうございます。","ENG":"Ah... thank you.","TWN":"啊……謝謝你。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BUTLER_PRIDE_NULL_NULL","text":{"KOREA":"별말씀을요. 변변찮은 다과도 차려드리지 못해 죄송할 따름입니다.","JPN":"どういたしまして。茶菓子もお出しできず、申し訳ないかぎりです。","ENG":"Think nothing of it. I only regret I couldn't offer you a proper tea service.","TWN":"哪裡的話，我只是遺憾沒能為你準備好茶點。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BUTLER_PRIDE_NULL_NULL","text":{"KOREA":"늙은이는 이만 자리를 비울 테니, 그레이스 님과 느긋하게 이야기 나누시길.","JPN":"老体はこれで失礼いたしますので、グレース様とごゆっくりお話しください。","ENG":"I'll take my leave now. Please enjoy a relaxed conversation with Dame Grace.","TWN":"那我就先告退，你可以和葛瑞絲小姐慢慢聊聊。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"목을 축일 차도 준비되었으니 이야기를 계속해보지요.","JPN":"喉を潤すお茶も来たことですし、お話を続けましょうか。","ENG":"Now that we've something to soothe the throat, shall we continue?","TWN":"準備好潤喉的茶了，我們繼續聊吧。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"혹, 제게 궁금한 게 있으신지요?","JPN":"私について聞きたいことはありますか？","ENG":"Is there anything else you wish to ask me?","TWN":"請問，你對我有什麼好奇的嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……앞서 만난 기사가 당신을 버밍엄 가문의 후계자라 말하더군요.","JPN":"……さっき会った騎士が、あなたをバーミンガム家の後継者と言っていました。","ENG":"...A knight I met earlier said you were heir to House Birmingham.","TWN":"……之前遇到的騎士說你是伯明罕家族的繼承人。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무언가 문제라도?","JPN":"何か問題でも？","ENG":"Is there a problem?","TWN":"有什麼問題嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"많습니다! 알렌 경은 가문의 후계자인 아내 분과 오래 전에 사별하셨다 말했어요!","JPN":"大ありです！　アレン卿から一族の後継者である夫人とはずいぶん前に死別されたと聞きました！","ENG":"A lot! Sir Allen said the heir of that house passed away years ago!","TWN":"很多！艾倫卿說他很久以前就和家族繼承人的妻子分開了！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"애당초, 버밍엄 가문은 이미 멸족한 가문입니다!","JPN":"そもそも、バーミンガム家はすでに滅亡しています！","ENG":"The Birmingham line was declared extinct!","TWN":"本來，伯明罕家族已經滅族了！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 그리 매섭게 노려보지 마시지요. 구태여 꺼낸 답변을 채 잇기가 두렵습니다.","JPN":"ふふ。そんなに恐い顔で睨まないでください。やっとのことで用意した答えをお話しすることが怖くなります。","ENG":"My, such a fierce glare. It almost makes me afraid to finish what I was about to say.","TWN":"呵呵。別那麼兇狠地盯著我嘛。我還怕接不上你特意提出來的回答呢。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"경의 추측대로 저는 그레이스 버밍엄이 아닙니다.","JPN":"卿の推測どおり、私はグレース・バーミンガムではありません。","ENG":"As you suspect, I am not Grace Birmingham.","TWN":"正如你所猜測的，我不是葛瑞絲·伯明罕。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"허나, 동시에 그레이스 버밍엄이기도 하지요.","JPN":"ですが、それと同時にグレース・バーミンガムでもあります。","ENG":"And yet, I am also Grace Birmingham.","TWN":"不過，同時我也是葛瑞絲·伯明罕。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"지금 저를 놀리시는 겁니까?","JPN":"からかっているのですか？","ENG":"Are you mocking me right now?","TWN":"現在是在耍我嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"섭섭한 말씀을 하시네요. 귀족이라는 작자가 어찌 이런 일에 장난을 치겠습니까?","JPN":"とんでもありません。貴族たるもの、このような場面で冗談など言いません。","ENG":"How disappointing. What sort of noble would joke about something so serious?","TWN":"你這話讓我感到遺憾。身為貴族的人怎麼會在這種事情上開玩笑呢？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그저 직접적인 사실을 밝힐 수 없을 뿐입니다.","JPN":"ただ、事実そのものを明かすことができないだけです。","ENG":"I simply cannot reveal the full truth so directly.","TWN":"只是無法直接揭露事實而已。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"여기서 제가 진실을 고한 들, 경께서 원하시는 진실에 다다를 순 없을 테니까요.","JPN":"それに、ここで私が真実を告げようとも、求めている真実にたどり着くことはできないでしょう。","ENG":"Even if I told you everything now, it wouldn't be the truth you seek.","TWN":"即使我在這裡說出真相，也無法達到你所期望的真相。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……아무래도, 제대로 답해주실 생각은 없어 보이는군요.","JPN":"……どうやら、ちゃんと答えてくれる気はなさそうですね。","ENG":"...So you have no intention of giving me a real answer.","TWN":"……看來，你並不打算好好回答我的問題。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"신경 써주셔서 감사합니다만, 이만 돌아가겠습니다.","JPN":"お気遣いありがとうございます。ですが、もう帰ります。","ENG":"Thank you for your concern, but I'll be taking my leave.","TWN":"多謝關照，不過我該回去了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};